const output = [];

const notifiedManagers = new Set();
const notifiedTeamLeads = new Set();

for (const item of $input.all()) {
  const {
    team_user_first_name,
    team_user_last_name,
    team_user_email,

    project_id,
    project_title,
    new_project_status,
    status_changed_at,

    project_manager_email,

    team_lead_email,
    team_lead_firstname,
    team_lead_lastname
  } = item.json;

  // ✅ Team member → every row
  if (team_user_email) {
    output.push({
      json: {
        firstname: team_user_first_name,
        lastname: team_user_last_name,
        email: team_user_email,
        role: 'team',
        project_title,
        project_status: new_project_status,
        status_changed_at
      }
    });
  }

  // ✅ Project manager → only once per project
  if (
    project_manager_email &&
    !notifiedManagers.has(project_id)
  ) {
    notifiedManagers.add(project_id);

    output.push({
      json: {
        firstname: team_user_first_name, // (keeping your original logic unchanged)
        lastname: team_user_last_name,
        email: project_manager_email,
        role: 'manager',
        project_title,
        project_status: new_project_status,
        status_changed_at
      }
    });
  }

  // ✅ Team lead → only once per project
  if (
    team_lead_email &&
    !notifiedTeamLeads.has(project_id)
  ) {
    notifiedTeamLeads.add(project_id);

    output.push({
      json: {
        firstname: team_lead_firstname,
        lastname: team_lead_lastname,
        email: team_lead_email,
        role: 'team_lead',
        project_title,
        project_status: new_project_status,
        status_changed_at
      }
    });
  }
}

return output;

